import { format, parseISO, formatDistanceToNow } from 'date-fns';
import { formatInTimeZone, fromZonedTime } from 'date-fns-tz';

const DATE_FMT     = 'dd-MMM-yyyy';
const DATETIME_FMT = 'dd-MMM-yyyy, hh:mm a';

/**
 * Parses a date-only API field into a Date object, stripping the time component
 * before calling parseISO so UTC→local timezone shift never affects the calendar date.
 * Use this wherever you need a Date for arithmetic or custom formatting on date-only fields.
 * For display only, prefer formatDate() which handles stripping internally.
 */
export function parseDateOnly(value: string | null | undefined): Date | null {
  if (!value) return null;
  try {
    return parseISO(value.substring(0, 10));
  } catch {
    return null;
  }
}

/**
 * Formats a date-only value (e.g. "1990-05-15" or "1990-05-15T00:00:00Z").
 * Strips the time component before parsing to prevent UTC→local timezone shift
 * on date-only fields that should represent a calendar date without timezone meaning.
 */
export function formatDate(value: string | null | undefined): string {
  if (!value) return '—';
  try {
    return format(parseISO(value.substring(0, 10)), DATE_FMT);
  } catch {
    return '—';
  }
}

/**
 * Formats a UTC datetime ISO string (e.g. "2026-01-17T09:30:00Z").
 * parseISO respects the Z suffix and converts to the browser's local timezone.
 */
export function formatDateTime(value: string | null | undefined): string {
  if (!value) return '—';
  try {
    return format(parseISO(value), DATETIME_FMT);
  } catch {
    return '—';
  }
}

/**
 * Returns a human-readable relative time string (e.g. "3 days ago").
 * Parses the ISO string and delegates to date-fns formatDistanceToNow.
 */
export function formatRelative(value: string | null | undefined): string {
  if (!value) return '—';
  try {
    return formatDistanceToNow(parseISO(value), { addSuffix: true });
  } catch {
    return '—';
  }
}

/**
 * Converts a UTC ISO string to a datetime-local input value in the given IANA timezone.
 * Used to pre-fill form inputs so the user sees times in their local timezone.
 * Returns "YYYY-MM-DDTHH:mm" (the format expected by <input type="datetime-local">).
 */
export function utcToZonedInput(utcString: string | null | undefined, timeZone: string): string {
  if (!utcString) return '';
  try {
    const src = utcString.endsWith('Z') ? utcString : utcString + 'Z';
    return formatInTimeZone(parseISO(src), timeZone, "yyyy-MM-dd'T'HH:mm");
  } catch {
    return '';
  }
}

/**
 * Converts a datetime-local input value (in the given IANA timezone) to a UTC ISO string.
 * Used to convert form-submitted times back to UTC before sending to the API.
 * Expects "YYYY-MM-DDTHH:mm" format (as produced by <input type="datetime-local">).
 */
export function zonedInputToUtc(localString: string | null | undefined, timeZone: string): string {
  if (!localString) return '';
  try {
    return fromZonedTime(localString, timeZone).toISOString();
  } catch {
    return '';
  }
}
